<h1 class="h3 mb-3">Laporan Penjualan</h1>
<div class="card shadow-sm border-0 mb-3"><div class="card-body"><form class="row g-3"><input type="hidden" name="page" value="laporan-penjualan"><div class="col-md-3"><label class="form-label">Dari</label><input class="form-control" type="date" name="from" value="<?= e($from) ?>"></div><div class="col-md-3"><label class="form-label">Sampai</label><input class="form-control" type="date" name="to" value="<?= e($to) ?>"></div><div class="col-md-6 d-flex align-items-end gap-2 flex-wrap"><button class="btn btn-primary">Filter</button><a class="btn btn-outline-dark" target="_blank" href="<?= e(url('index.php?page=laporan-print&type=penjualan&from=' . urlencode($from) . '&to=' . urlencode($to))) ?>">Cetak / PDF</a><a class="btn btn-outline-success" href="<?= e(url('index.php?page=laporan-penjualan-excel&from=' . urlencode($from) . '&to=' . urlencode($to))) ?>">Export Excel</a></div></form></div></div>
