  <div class="col-md-4"><div class="card shadow-sm border-0"><div class="card-body"><div class="text-muted small">Summary Total</div><div class="h5 mb-0"><?= e(fmt_rp($summary['total'] ?? 0)) ?></div></div></div></div>
  <div class="col-md-4"><div class="card shadow-sm border-0"><div class="card-body"><div class="text-muted small">Summary Dibayar</div><div class="h5 mb-0"><?= e(fmt_rp($summary['dibayar'] ?? 0)) ?></div></div></div></div>
  <div class="col-md-4"><div class="card shadow-sm border-0"><div class="card-body"><div class="text-muted small">Summary Sisa</div><div class="h5 mb-0"><?= e(fmt_rp($summary['sisa'] ?? 0)) ?></div></div></div></div>
