<div class="card shadow-sm border-0"><div class="card-body table-responsive"><table class="table table-striped"><thead><tr><th>Tanggal</th><th>Referensi</th><th>Pihak</th><th class="text-end">Total</th><th class="text-end">Dibayar</th><th class="text-end">Sisa</th><th>Status</th></tr></thead><tbody><?php foreach($rows as $r): ?><tr><td><?= e(date('d-m-Y', strtotime($r['tanggal']))) ?></td><td><?= e($r['kode_penjualan']) ?></td><td><?= e($r['nama_pelanggan'] ?? '-') ?></td><td class="text-end"><?= e(fmt_rp($r['total'])) ?></td><td class="text-end"><?= e(fmt_rp($r['dibayar'])) ?></td><td class="text-end"><?= e(fmt_rp($r['sisa'])) ?></td><td><?= e($r['status_pembayaran']) ?></td></tr><?php endforeach; if(!$rows): ?><tr><td colspan="7" class="text-center text-muted py-4">Tidak ada data.</td></tr><?php endif; ?></tbody></table></div></div>
